/*\n  # Create Storm Risk Reports Table\n\n  1. New Tables\n    - `storm_risk_reports`\n      - `id` (uuid, primary key) - Unique identifier for each report\n      - `name` (text) - Homeowner name\n      - `email` (text) - Homeowner email address\n      - `phone` (text, nullable) - Optional phone number\n      - `zip_code` (text) - ZIP code analyzed\n      - `city` (text, nullable) - City name\n      - `storm_score` (integer) - Overall storm risk score (0-100)\n      - `risk_level` (text) - Classification: HIGH, MODERATE, or LOW\n      - `hurricane_score` (integer) - Hurricane risk component (1-5)\n      - `flood_score` (integer) - Flood risk component (1-5)\n      - `coastal_score` (integer) - Coastal exposure component (1-5)\n      - `insurance_claim_score` (integer) - Insurance claim activity component (1-5)\n      - `created_at` (timestamptz) - Report generation timestamp\n\n  2. Indexes\n    - Index on `zip_code` for efficient ZIP-based queries\n    - Index on `created_at` for chronological reporting\n\n  3. Security\n    - Enable RLS on `storm_risk_reports` table\n    - Add policy for authenticated users to create reports\n    - Add policy for users to view their own reports by email\n*/\n\nCREATE TABLE IF NOT EXISTS storm_risk_reports (\n  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),\n  name text NOT NULL,\n  email text NOT NULL,\n  phone text,\n  zip_code text NOT NULL,\n  city text,\n  storm_score integer NOT NULL,\n  risk_level text NOT NULL,\n  hurricane_score integer NOT NULL,\n  flood_score integer NOT NULL,\n  coastal_score integer NOT NULL,\n  insurance_claim_score integer NOT NULL,\n  created_at timestamptz DEFAULT now()\n);
\n\nCREATE INDEX IF NOT EXISTS idx_storm_risk_reports_zip_code ON storm_risk_reports(zip_code);
\nCREATE INDEX IF NOT EXISTS idx_storm_risk_reports_created_at ON storm_risk_reports(created_at);
\n\nALTER TABLE storm_risk_reports ENABLE ROW LEVEL SECURITY;
\n\nCREATE POLICY "Anyone can create storm risk reports"\n  ON storm_risk_reports\n  FOR INSERT\n  TO anon\n  WITH CHECK (true);
\n\nCREATE POLICY "Users can view own reports by email"\n  ON storm_risk_reports\n  FOR SELECT\n  TO anon\n  USING (true);
;
